public enum PdfError: Swift.Error {

    
    
    case FileNotFound(path: String
    )
    case InvalidPdf(detail: String
    )
    case PasswordProtected
    case PageOutOfRange(requested: UInt32, total: UInt32
    )
    case RenderingFailed(detail: String
    )
    case UnsupportedColorspace(name: String
    )
    case DiffPageCountMismatch(left: UInt32, right: UInt32
    )
    case DiffPageSizeMismatch(page: UInt32
    )
    case ReportGenerationFailed(detail: String
    )
    case InternalError(detail: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypePdfError: FfiConverterRustBuffer {
    typealias SwiftType = PdfError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> PdfError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .FileNotFound(
            path: try FfiConverterString.read(from: &buf)
            )
        case 2: return .InvalidPdf(
            detail: try FfiConverterString.read(from: &buf)
            )
        case 3: return .PasswordProtected
        case 4: return .PageOutOfRange(
            requested: try FfiConverterUInt32.read(from: &buf), 
            total: try FfiConverterUInt32.read(from: &buf)
            )
        case 5: return .RenderingFailed(
            detail: try FfiConverterString.read(from: &buf)
            )
        case 6: return .UnsupportedColorspace(
            name: try FfiConverterString.read(from: &buf)
            )
        case 7: return .DiffPageCountMismatch(
            left: try FfiConverterUInt32.read(from: &buf), 
            right: try FfiConverterUInt32.read(from: &buf)
            )
        case 8: return .DiffPageSizeMismatch(
            page: try FfiConverterUInt32.read(from: &buf)
            )
        case 9: return .ReportGenerationFailed(
            detail: try FfiConverterString.read(from: &buf)
            )
        case 10: return .InternalError(
            detail: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: PdfError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .FileNotFound(path):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(path, into: &buf)
            
        
        case let .InvalidPdf(detail):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(detail, into: &buf)
            
        
        case .PasswordProtected:
            writeInt(&buf, Int32(3))
        
        
        case let .PageOutOfRange(requested,total):
